/**
 * Configuration options for the 0xarchive client
 */
export interface ClientOptions {
  /** Your 0xarchive API key */
  apiKey: string;
  /** Base URL for the API (defaults to https://api.0xarchive.io) */
  baseUrl?: string;
  /** Request timeout in milliseconds (defaults to 30000) */
  timeout?: number;
}

/**
 * Standard API response wrapper
 */
export interface ApiResponse<T> {
  success: boolean;
  data: T;
  count: number;
  request_id: string;
}

/**
 * Pagination parameters for list endpoints
 */
export interface PaginationParams {
  /** Maximum number of results to return */
  limit?: number;
  /** Number of results to skip */
  offset?: number;
}

/**
 * Time range parameters for historical queries
 */
export interface TimeRangeParams extends PaginationParams {
  /** Start timestamp (Unix ms or ISO string) */
  start?: number | string;
  /** End timestamp (Unix ms or ISO string) */
  end?: number | string;
}

// =============================================================================
// Order Book Types
// =============================================================================

/** A price level in the order book [price, size] */
export type PriceLevel = [string, string];

/**
 * Order book snapshot
 */
export interface OrderBook {
  coin: string;
  timestamp: number;
  bids: PriceLevel[];
  asks: PriceLevel[];
  mid_price: string;
  spread: string;
  spread_bps: string;
}

export interface GetOrderBookParams {
  /** Timestamp to get order book at (Unix ms or ISO string) */
  timestamp?: number | string;
  /** Number of price levels to return per side */
  depth?: number;
}

export interface OrderBookHistoryParams extends TimeRangeParams {
  /** Number of price levels to return per side */
  depth?: number;
}

// =============================================================================
// Trades Types
// =============================================================================

/**
 * Trade/fill record
 */
export interface Trade {
  id: string;
  coin: string;
  side: 'buy' | 'sell';
  price: string;
  size: string;
  value: string;
  timestamp: number;
  trade_type: string;
}

export interface GetTradesParams extends TimeRangeParams {
  /** Filter by side */
  side?: 'buy' | 'sell';
}

// =============================================================================
// Candles Types
// =============================================================================

/**
 * OHLCV candle
 */
export interface Candle {
  coin: string;
  interval: string;
  timestamp: number;
  open: string;
  high: string;
  low: string;
  close: string;
  volume: string;
  trades: number;
}

export type CandleInterval = '1m' | '5m' | '15m' | '1h' | '4h' | '1d';

export interface GetCandlesParams extends TimeRangeParams {
  /** Candle interval */
  interval?: CandleInterval;
}

// =============================================================================
// Instruments Types
// =============================================================================

/**
 * Trading instrument metadata
 */
export interface Instrument {
  coin: string;
  name: string;
  sz_decimals: number;
  max_leverage: number;
  only_isolated: boolean;
  is_active: boolean;
}

// =============================================================================
// Funding Types
// =============================================================================

/**
 * Funding rate record
 */
export interface FundingRate {
  coin: string;
  funding_rate: string;
  premium: string;
  timestamp: number;
}

// =============================================================================
// Open Interest Types
// =============================================================================

/**
 * Open interest record
 */
export interface OpenInterest {
  coin: string;
  open_interest: string;
  timestamp: number;
}

// =============================================================================
// WebSocket Types
// =============================================================================

/** WebSocket channel types */
export type WsChannel = 'orderbook' | 'trades' | 'ticker' | 'all_tickers';

/** Subscribe message from client */
export interface WsSubscribe {
  op: 'subscribe';
  channel: WsChannel;
  coin?: string;
}

/** Unsubscribe message from client */
export interface WsUnsubscribe {
  op: 'unsubscribe';
  channel: WsChannel;
  coin?: string;
}

/** Ping message from client */
export interface WsPing {
  op: 'ping';
}

/** Client message union type */
export type WsClientMessage = WsSubscribe | WsUnsubscribe | WsPing;

/** Subscription confirmed from server */
export interface WsSubscribed {
  type: 'subscribed';
  channel: WsChannel;
  coin?: string;
}

/** Unsubscription confirmed from server */
export interface WsUnsubscribed {
  type: 'unsubscribed';
  channel: WsChannel;
  coin?: string;
}

/** Pong response from server */
export interface WsPong {
  type: 'pong';
}

/** Error from server */
export interface WsError {
  type: 'error';
  message: string;
}

/** Data message from server */
export interface WsData<T = unknown> {
  type: 'data';
  channel: WsChannel;
  coin: string;
  data: T;
}

/** Server message union type */
export type WsServerMessage = WsSubscribed | WsUnsubscribed | WsPong | WsError | WsData;

/** WebSocket connection options */
export interface WsOptions {
  /** API key for authentication */
  apiKey: string;
  /** WebSocket URL (defaults to wss://ws.0xarchive.io) */
  wsUrl?: string;
  /** Auto-reconnect on disconnect (defaults to true) */
  autoReconnect?: boolean;
  /** Reconnect delay in ms (defaults to 1000) */
  reconnectDelay?: number;
  /** Maximum reconnect attempts (defaults to 10) */
  maxReconnectAttempts?: number;
  /** Ping interval in ms (defaults to 30000) */
  pingInterval?: number;
}

/** WebSocket connection state */
export type WsConnectionState = 'connecting' | 'connected' | 'disconnected' | 'reconnecting';

/** WebSocket event handlers */
export interface WsEventHandlers {
  onOpen?: () => void;
  onClose?: (code: number, reason: string) => void;
  onError?: (error: Error) => void;
  onMessage?: (message: WsServerMessage) => void;
  onStateChange?: (state: WsConnectionState) => void;
}

// =============================================================================
// Error Types
// =============================================================================

/**
 * API error response
 */
export interface ApiError {
  code: number;
  error: string;
}

/**
 * SDK error class
 */
export class OxArchiveError extends Error {
  code: number;
  requestId?: string;

  constructor(message: string, code: number, requestId?: string) {
    super(message);
    this.name = 'OxArchiveError';
    this.code = code;
    this.requestId = requestId;
  }
}
